import{_ as a,H as t,f as n,i as s}from"./chunks/framework.Usbf9s97.js";const u=JSON.parse('{"title":"项目介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1779801822000}'),l={name:"guide/index.md"};function i(o,e,r,p,d,c){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="项目介绍" tabindex="-1">项目介绍 <a class="header-anchor" href="#项目介绍" aria-label="Permalink to &quot;项目介绍&quot;">​</a></h1><p>本项目是一套以 <strong>Electron + Vue 3 + Python（FastAPI）</strong> 为核心的桌面应用脚手架，目标是让开发者在一份代码中同时拥有：</p><ul><li>跨平台桌面壳（Electron）</li><li>现代前端开发体验（Vite + Vue 3 + Pinia + Tailwind 4）</li><li>强大的本地服务能力（Python FastAPI 后端）</li></ul><h2 id="为什么需要这套模板" tabindex="-1">为什么需要这套模板 <a class="header-anchor" href="#为什么需要这套模板" aria-label="Permalink to &quot;为什么需要这套模板&quot;">​</a></h2><p>传统的 Electron 应用只有 Node.js 与渲染层两端。若业务需要：</p><ul><li>调用大量已有 Python 生态（数据处理、机器学习、文件解析）</li><li>需要独立的本地服务进程供其他工具消费</li><li>想把业务逻辑沉淀在 Python 侧而非 Node 侧</li></ul><p>此时简单的 <code>child_process.spawn</code> 不足以支撑：进程崩溃恢复、端口冲突、请求超时、双向回调、安装包内嵌打包二进制等，都是难点。本模板把这些都做成默认值。</p><h2 id="三端组成" tabindex="-1">三端组成 <a class="header-anchor" href="#三端组成" aria-label="Permalink to &quot;三端组成&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端</th><th>技术栈</th><th>角色</th></tr></thead><tbody><tr><td><strong>Electron 主进程</strong></td><td>Electron 39 + electron-vite</td><td>桌面壳、子进程管理、IPC 路由、Python 服务监督</td></tr><tr><td><strong>Vue 渲染端</strong></td><td>Vue 3 + Pinia + Vue Router + Tailwind 4</td><td>用户界面、调用主进程能力与 Python API</td></tr><tr><td><strong>Python 后端</strong></td><td>FastAPI + Uvicorn + Pydantic</td><td>业务执行、HTTP / WebSocket 服务、可独立打包</td></tr></tbody></table><p>每端的代码都按职责清晰分目录，互不耦合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>new-template/</span></span>
<span class="line"><span>├── electron/          # 主进程与 preload</span></span>
<span class="line"><span>├── web/               # Vue 渲染端</span></span>
<span class="line"><span>├── python_backend/    # Python FastAPI 服务</span></span>
<span class="line"><span>├── scripts/           # 构建与同步脚本</span></span>
<span class="line"><span>└── gh-pages/          # 项目介绍文档（VitePress）</span></span></code></pre></div><h2 id="通信总览" tabindex="-1">通信总览 <a class="header-anchor" href="#通信总览" aria-label="Permalink to &quot;通信总览&quot;">​</a></h2><p>三端通过三条独立的通道协同：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>渲染层 (Vue)</span></span>
<span class="line"><span>   │  IPC               HTTP /api/bridge       WebSocket</span></span>
<span class="line"><span>   ▼                    ▼                       ▲</span></span>
<span class="line"><span>Electron 主进程 ────────────────→ Python 后端 ──┘</span></span>
<span class="line"><span>        ◀────────────── WS /ws/electron ───────</span></span></code></pre></div><ul><li><strong>Renderer ↔ Main</strong>：标准 Electron IPC，用于状态查询、连接控制</li><li><strong>Renderer → Python</strong>：HTTP <code>/api/bridge</code>，同步业务调用</li><li><strong>Python → Renderer</strong>：WebSocket 反向通道，主进程作为代理把指令分发到渲染层</li></ul><p>详细分层与超时模型见 <a href="/electron-python-template/guide/architecture">架构总览</a>。</p><h2 id="默认提供的能力" tabindex="-1">默认提供的能力 <a class="header-anchor" href="#默认提供的能力" aria-label="Permalink to &quot;默认提供的能力&quot;">​</a></h2><ul><li>自动启动 / 停止 Python 子进程，崩溃后指数退避重连</li><li>端口探测：默认 47821 被占用时自动 +1 探测，最多 50 次</li><li>守护进程模式：二次启动复用驻留进程，元数据写到用户目录</li><li>DI 容器与 IPC 中间件管道（错误边界、日志、计时、指标、参数校验）</li><li>WebSocket 反向通信与回调管理</li><li>electron-builder + PyInstaller 一键打包 Win / Mac / Linux</li><li>VitePress 项目文档（即本站）</li></ul><h2 id="接下来" tabindex="-1">接下来 <a class="header-anchor" href="#接下来" aria-label="Permalink to &quot;接下来&quot;">​</a></h2><ul><li>想跑起来：<a href="/electron-python-template/guide/quick-start">快速开始</a></li><li>想了解每端：<a href="/electron-python-template/guide/main-process">主进程入口</a> · <a href="/electron-python-template/guide/web-structure">Web 目录结构</a> · <a href="/electron-python-template/guide/python-server">路由与中间件</a></li><li>想看怎么开发与发布：<a href="/electron-python-template/guide/development">开发流程</a> · <a href="/electron-python-template/guide/build">打包发布</a></li></ul>`,20)])])}const g=a(l,[["render",i]]);export{u as __pageData,g as default};
